import React from "react";
//import Helmet from "react-helmet";
import Link from "gatsby-link";

import "./index.css";

export default ({ location, children }) => (
  <div>
    {/*TODO: <Helmet>*/}
    <nav>
      <h1>
        <a href="http://davidhartsough.com">David<span id="last-name"> Hartsough</span></a>
        <span> &mdash; {
          (location.pathname === '/')
            ? "Writings"
            : <Link to="/">Writings</Link>
        }</span>
      </h1>
    </nav>
    <main>
      {children()}
    </main>
  </div>
);



